// ─────────────────────────────────────────────────────────────────────
// Build combined weekly email:
//   SECTION 1 — Competitor Intelligence (6 competitors)
//   SECTION 2 — Business Opportunities (5 sectors)
// ─────────────────────────────────────────────────────────────────────

const items = $input.all();
// items[0].json contains the aggregated sector briefs array
// Competitor briefs were passed forward as competitor_briefs field
const sectorBriefs     = items.map(i => i.json).filter(b => b && !b.error);
const competitorBriefs = items[0]?.json?.competitor_briefs || [];

const now = new Date().toLocaleDateString('en-GB', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

// ── Colour helpers ────────────────────────────────────────────────────
const impactColour  = l => l === 'High' ? '#c0392b' : l === 'Medium' ? '#d17a00' : '#2d8a4e';
const urgencyColour = u => u === 'Immediate' ? '#c0392b' : '#4a5066';

// ── Shared card styles ────────────────────────────────────────────────
const cardStyle = colour =>
  `border-left:3px solid ${colour};padding:10px 14px;margin-bottom:10px;background:#fafafa;border-radius:4px`;

// ── Section header ────────────────────────────────────────────────────
const sectionHeader = (title, subtitle) => `
  <div style="margin-bottom:32px">
    <h2 style="font-family:Georgia,serif;font-size:18px;color:#0f1117;
               border-bottom:2px solid #e4e7f0;padding-bottom:8px;margin-bottom:4px">
      ${title}
    </h2>
    <p style="font-size:11px;color:#9299b0;margin:0 0 16px">${subtitle}</p>
`;

// ── Extract takeaway text ─────────────────────────────────────────────
const extractTakeaway = raw => {
  if (!raw) return '';
  const marker = raw.indexOf('── EXECUTIVE TAKEAWAY');
  if (marker === -1) return raw.slice(-400);
  return raw.slice(marker).replace(/── EXECUTIVE TAKEAWAY[─]*/g, '').trim();
};

const takeawayBlock = text => !text ? '' : `
  <div style="background:#0f1117;color:#fff;border-radius:6px;
              padding:16px 18px;margin-top:16px">
    <div style="font-size:10px;font-weight:600;letter-spacing:0.1em;
                text-transform:uppercase;color:rgba(255,255,255,0.45);margin-bottom:8px">
      Executive Takeaway
    </div>
    <div style="font-size:13px;line-height:1.7;color:rgba(255,255,255,0.9)">${text}</div>
  </div>
`;

// ─────────────────────────────────────────────────────────────────────
// SECTION 1 — Competitor Intelligence
// ─────────────────────────────────────────────────────────────────────

const renderCompetitorBrief = brief => {
  if (!brief || brief.error) return '';
  const signals  = brief.signals || [];
  const high     = signals.filter(s => s.impact_level === 'High');
  const medium   = signals.filter(s => s.impact_level === 'Medium');
  const low      = signals.filter(s => s.impact_level === 'Low');
  const takeaway = extractTakeaway(brief.executive_takeaway || brief.final_brief || '');

  const renderGroup = (items, level) => {
    if (!items.length) return '';
    const colour = impactColour(level);
    return `
      <div style="margin-bottom:12px">
        <div style="font-size:10px;font-weight:600;letter-spacing:0.08em;
                    text-transform:uppercase;color:${colour};margin-bottom:6px">
          ${level} Impact
        </div>
        ${items.map(s => `
          <div style="${cardStyle(colour)}">
            <div style="font-weight:600;font-size:13px">
              ${s.url
                ? `<a href="${s.url}" style="color:#0f1117;text-decoration:none">${s.title}</a>`
                : (s.title || '')}
            </div>
            <div style="font-size:12px;color:#4a5066;margin-top:4px">
              ${s.source || ''}
              ${s.published_at ? ' &nbsp;|&nbsp; ' + s.published_at : ''}
              ${s.strategic_link ? ' &nbsp;|&nbsp; ' + s.strategic_link : ''}
            </div>
            <div style="font-size:12px;color:#4a5066;margin-top:4px">${s.impact_summary || ''}</div>
            <div style="font-size:11px;color:#9299b0;margin-top:4px">${s.confidence || 0}/10 confidence</div>
          </div>
        `).join('')}
      </div>
    `;
  };

  return `
    <div style="margin-bottom:28px;padding-bottom:24px;border-bottom:1px solid #e4e7f0">
      <h3 style="font-size:14px;font-weight:600;color:#0f1117;margin:0 0 10px">
        ${brief.subject || brief.competitor || ''}
      </h3>
      ${!signals.length
        ? '<p style="font-size:12px;color:#9299b0">No signals found this period.</p>'
        : renderGroup(high,'High') + renderGroup(medium,'Medium') + renderGroup(low,'Low')
      }
      ${takeawayBlock(takeaway)}
    </div>
  `;
};

const competitorSection =
  sectionHeader('Competitor Intelligence', 'Competitor moves from the past 7 days') +
  (competitorBriefs.length
    ? competitorBriefs.map(renderCompetitorBrief).join('')
    : '<p style="font-size:13px;color:#9299b0">No competitor data available.</p>') +
  '</div>';

// ─────────────────────────────────────────────────────────────────────
// SECTION 2 — Business Opportunities
// ─────────────────────────────────────────────────────────────────────

const renderTenders = tenders => {
  if (!tenders || !tenders.length)
    return '<p style="font-size:12px;color:#9299b0">No live EU tenders this period.</p>';
  return tenders.map(t => `
    <div style="${cardStyle(impactColour(t.impact_level))}">
      <div style="font-weight:600;font-size:13px">
        ${t.url
          ? `<a href="${t.url}" style="color:#0f1117;text-decoration:none">${t.title}</a>`
          : (t.title || '')}
      </div>
      <div style="font-size:11px;color:#4a5066;margin-top:4px">
        ${t.country ? t.country + ' &nbsp;|&nbsp; ' : ''}
        ${t.value   ? t.value + ' &nbsp;|&nbsp; ' : ''}
        Deadline: <strong>${t.deadline || 'N/A'}</strong>
        &nbsp;|&nbsp;
        <span style="color:${urgencyColour(t.deadline_urgency)}">${t.deadline_urgency || ''}</span>
      </div>
      <div style="font-size:12px;color:#4a5066;margin-top:4px">${t.bid_fit_summary || ''}</div>
      ${t.recommended_action
        ? `<div style="font-size:11px;color:#1a3cff;margin-top:4px">→ ${t.recommended_action}</div>`
        : ''}
    </div>
  `).join('');
};

const renderPrivate = privates => {
  if (!privates || !privates.length)
    return '<p style="font-size:12px;color:#9299b0">No private expansion signals this period.</p>';
  return privates.map(p => `
    <div style="${cardStyle('#7b2d8b')}">
      <div style="font-weight:600;font-size:13px">
        ${p.url
          ? `<a href="${p.url}" style="color:#0f1117;text-decoration:none">${p.title}</a>`
          : (p.title || '')}
      </div>
      <div style="font-size:11px;color:#4a5066;margin-top:4px">
        ${p.source || ''}
        ${p.published_at ? ' &nbsp;|&nbsp; ' + p.published_at : ''}
        ${p.signal_type  ? ' &nbsp;|&nbsp; ' + p.signal_type.replace(/_/g,' ') : ''}
      </div>
      <div style="font-size:12px;color:#4a5066;margin-top:4px">${p.bid_fit_summary || ''}</div>
      ${p.recommended_action
        ? `<div style="font-size:11px;color:#1a3cff;margin-top:4px">→ ${p.recommended_action}</div>`
        : ''}
    </div>
  `).join('');
};

const renderSectorBrief = brief => {
  if (!brief || brief.error) return '';
  const tenders  = brief.tenders  || [];
  const privates = brief.private_opportunities || [];
  const takeaway = extractTakeaway(brief.executive_takeaway || brief.final_brief || '');
  return `
    <div style="margin-bottom:28px;padding-bottom:24px;border-bottom:1px solid #e4e7f0">
      <h3 style="font-size:14px;font-weight:600;color:#0f1117;margin:0 0 12px">
        ${brief.subject || ''}
      </h3>
      <div style="font-size:10px;font-weight:600;letter-spacing:0.08em;text-transform:uppercase;
                  color:#1a3cff;margin-bottom:8px">Live EU Tenders</div>
      ${renderTenders(tenders)}
      <div style="font-size:10px;font-weight:600;letter-spacing:0.08em;text-transform:uppercase;
                  color:#7b2d8b;margin:14px 0 8px">Private Opportunities</div>
      ${renderPrivate(privates)}
      ${takeawayBlock(takeaway)}
    </div>
  `;
};

const opportunitiesSection =
  sectionHeader('Business Opportunities', 'Live tenders and private expansion signals from the past 7 days') +
  (sectorBriefs.length
    ? sectorBriefs.map(renderSectorBrief).join('')
    : '<p style="font-size:13px;color:#9299b0">No opportunity data available.</p>') +
  '</div>';

// ─────────────────────────────────────────────────────────────────────
// Assemble full email
// ─────────────────────────────────────────────────────────────────────

const html = `
<!DOCTYPE html>
<html>
<body style="font-family:'Helvetica Neue',Arial,sans-serif;background:#f7f8fc;margin:0;padding:0">
  <div style="max-width:700px;margin:0 auto;background:#fff;border:1px solid #e4e7f0">

    <div style="background:#0f1117;padding:24px 32px">
      <div style="font-family:Georgia,serif;font-size:22px;color:#fff">Strategic Radar</div>
      <div style="font-size:11px;color:rgba(255,255,255,0.5);margin-top:4px;
                  letter-spacing:0.06em;text-transform:uppercase">
        Weekly Intelligence Brief
      </div>
    </div>

    <div style="padding:32px">
      <p style="font-size:13px;color:#9299b0;margin:0 0 36px">${now}</p>
      ${competitorSection}
      <div style="height:32px"></div>
      ${opportunitiesSection}
      <hr style="border:none;border-top:1px solid #e4e7f0;margin:32px 0">
      <p style="font-size:11px;color:#9299b0;text-align:center">
        Generated by Strategic Radar &nbsp;·&nbsp; PARTTEAM &amp; OEMKIOSKS
      </p>
    </div>

  </div>
</body>
</html>
`;

const dateStamp = new Date().toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'numeric'});
return [{ json: {
  html,
  subject_line: `Strategic Radar — Weekly Brief — ${dateStamp}`
} }];
